import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function LabourDashboard() {

  const [requests, setRequests] = useState([]);

  const user = JSON.parse(localStorage.getItem("user"));

  const fetchRequests = async () => {

    const res = await axios.get(
      `http://localhost:5000/api/request/labour/${user._id}`
    );

    setRequests(res.data);
  };


  // RESPOND
  const respond = async (id) => {

    const price = prompt("Enter price");
    const action = prompt("Accepted / Rejected");

    await axios.put(
      `http://localhost:5000/api/request/labour-response/${id}`,
      { price, action }
    );

    fetchRequests();
  };

  return (

    <div>

      <Navbar />

      <div className="container">

        <h2>Labour Dashboard</h2>

        <div className="grid">

          {requests.length === 0 ? (

            <div className="card">No requests yet</div>

          ) : (

            requests.map(r => (

              <div className="card" key={r._id}>

                <h3>{r.customerName}</h3>
                <p>Work: {r.workType}</p>
                <p>Location: {r.location}</p>

                <p>Status: {r.status}</p>

                <button className="btn btn-success" onClick={() => respond(r._id)}>
                  Respond
                </button>

              </div>

            ))

          )}

        </div>

      </div>

    </div>
  );
}
